example.code:
import { vi, describe, it, expect, afterEach } from 'vitest';
import { sendEmail } from '../services/email';
import { registerUser } from '../services/user';

vi.mock('../services/email');

afterEach(() => vi.clearAllMocks());

it('sends welcome email on registration', async () => {
  await registerUser({ email: 'new@example.com' });
  expect(sendEmail).toHaveBeenCalledOnce();
  expect(sendEmail).toHaveBeenCalledWith(expect.objectContaining({
    to: 'new@example.com',
  }));
});

// Define the interface in production code
type Mailer interface {
    Send(to, subject, body string) error
}

// Manual test mock
type mockMailer struct {
    calls []string
    err   error
}

func (m *mockMailer) Send(to, subject, body string) error {
    m.calls = append(m.calls, to)
    return m.err
}

func TestUserService_Register(t *testing.T) {
    mailer := &mockMailer{}
    svc := NewUserService(mailer)
    svc.Register("user@example.com")
    if len(mailer.calls) != 1 || mailer.calls[0] != "user@example.com" {
        t.Errorf("expected one email to user@example.com, got %v", mailer.calls)
    }
}
